const B64 = "";

// Lazy, per-word decode. The common match path (exact token equality, then
// Jaro-Winkler typo matching) never needs vectors, so nothing here runs at
// import. On the first semantic lookup we decode the int8 blob and build a
// word->row index once (~11ms), then decode each requested word's
// unit-normalized vector on demand and cache it — so we never build all ~30k
// vectors up front (that was ~25ms of mostly-wasted work every SW cold start).
let Q = null; // Int8Array of quantized components, or null until loaded
let INDEX = null; // word -> row index
const CACHE = new Map(); // word -> Float32Array(DIM) (unit-normalized) or null (miss)

function ensureLoaded() {
  if (Q) return;
  const bin = atob(B64);
  Q = new Int8Array(bin.length);
  for (let i = 0; i < bin.length; i++) Q[i] = (bin.charCodeAt(i) << 24) >> 24;
  INDEX = new Map();
  for (let i = 0; i < WORDS.length; i++) INDEX.set(WORDS[i], i);
}

// Decode (and cache) a single word's unit-normalized vector, so cosine is a
// plain dot product. Returns null (also cached) when the word is out of vocab.
function decode(word) {
  if (CACHE.has(word)) return CACHE.get(word);
  ensureLoaded();
  const i = INDEX.get(word);
  if (i === undefined) {
    CACHE.set(word, null);
    return null;
  }
  const off = i * DIM;
  const v = new Float32Array(DIM);
  let norm = 0;
  for (let d = 0; d < DIM; d++) { const x = Q[off + d] * SCALE; v[d] = x; norm += x * x; }
  norm = Math.sqrt(norm) || 1;
  for (let d = 0; d < DIM; d++) v[d] /= norm;
  CACHE.set(word, v);
  return v;
}

// Look up a word, tolerant of the matcher's naive singularize() (which can strip
// or mangle a trailing "s", e.g. glasses->glasse, trousers->trouser). Falls back
// to the plural and singular vocab forms so those tokens still resolve.
function getVec(w) {
  let v = decode(w);
  if (!v && w.length > 2) v = decode(w + "s");
  if (!v && w.endsWith("s")) v = decode(w.slice(0, -1));
  return v || null;
}

// Cosine similarity of two words (0 if either is out of vocabulary).
export function wordCosine(a, b) {
  const A = getVec(a);
  const B = getVec(b);
  if (!A || !B) return 0;
  let dot = 0;
  for (let d = 0; d < DIM; d++) dot += A[d] * B[d];
  return dot;
}
